package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testGetIgnoreEmptyLines_Default() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertTrue(format.getIgnoreEmptyLines());
    }

    @Test
    public void testGetIgnoreEmptyLines_WithIgnoreEmptyLinesTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreEmptyLines(true);
        assertTrue(format.getIgnoreEmptyLines());
    }

    @Test
    public void testGetIgnoreEmptyLines_WithIgnoreEmptyLinesFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreEmptyLines(false);
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    public void testGetIgnoreEmptyLines_ExcelConstant() {
        CSVFormat format = CSVFormat.EXCEL;
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    public void testGetIgnoreEmptyLines_MySQLConstant() {
        CSVFormat format = CSVFormat.MYSQL;
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    public void testGetIgnoreEmptyLines_PostgreSQLCsvConstant() {
        CSVFormat format = CSVFormat.POSTGRESQL_CSV;
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    public void testGetIgnoreEmptyLines_PostgreSQLTextConstant() {
        CSVFormat format = CSVFormat.POSTGRESQL_TEXT;
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    public void testGetIgnoreEmptyLines_Rfc4180Constant() {
        CSVFormat format = CSVFormat.RFC4180;
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    public void testGetIgnoreEmptyLines_TdfConstant() {
        CSVFormat format = CSVFormat.TDF;
        // TDF is DEFAULT withIgnoreSurroundingSpaces(), ignoreEmptyLines is unchanged from DEFAULT
        assertTrue(format.getIgnoreEmptyLines());
    }
}
